export function findChapter(slug) {
  return PROVERBS_CHAPTERS.find(c => c.slug === slug) || null;
}

export function adjacentChapters(slug) {
  const idx = PROVERBS_CHAPTERS.findIndex(c => c.slug === slug);
  return {
    prev: idx > 0 ? PROVERBS_CHAPTERS[idx - 1] : null,
    next: idx >= 0 && idx < PROVERBS_CHAPTERS.length - 1 ? PROVERBS_CHAPTERS[idx + 1] : null,
  };
}
